package pt.isep.enorm.ref.service.generated;

/*Generated by MPS */

import org.springframework.transaction.annotation.Transactional;
import pt.isep.enorm.ref.domain.enums.TriggerEvent;
import java.util.List;
import java.util.Locale;
import pt.isep.enorm.ref.domain.enums.ConditionOperator;
import pt.isep.enorm.ref.domain.enums.ModerationDecision;
import pt.isep.enorm.ref.domain.enums.ModerationMode;

@Transactional(readOnly = true)
public abstract class GeneratedModerationService {
  protected GeneratedModerationModel.PolicySpec policyFor(final String targetType, final TriggerEvent trigger) {
    return GeneratedModerationModel.POLICIES.stream().filter((policy) -> policy.getTrigger() == trigger).filter((policy) -> targetMatches(policy, targetType)).findFirst().orElse(null);
  }

  protected boolean targetMatches(GeneratedModerationModel.PolicySpec policy, String targetType) {
    if (targetType == null || targetType.isBlank()) {
      return true;
    }
    return targetType.equals(policy.getResourceTarget()) || targetType.equals(policy.getFeedbackTarget());
  }

  protected GeneratedModerationModel.AutomationRuleSpec primaryRule(GeneratedModerationModel.PolicySpec policy) {
    if (policy == null || policy.getAutomationRules().isEmpty()) {
      return null;
    }
    return policy.getAutomationRules().get(0);
  }

  protected GeneratedModerationModel.ActionSpec primaryAction(GeneratedModerationModel.AutomationRuleSpec rule) {
    return (rule == null || rule.getActions().isEmpty() ? null : rule.getActions().get(0));
  }

  protected boolean triggerMatches(GeneratedModerationModel.PolicySpec policy, TriggerEvent actualTrigger) {
    return policy != null && actualTrigger == policy.getTrigger();
  }

  protected List<String> findMatchedKeywords(String content, GeneratedModerationModel.AutomationRuleSpec rule) {
    if (content == null || content.isBlank() || rule == null) {
      return List.of();
    }
    final String normalizedContent = content.toLowerCase(Locale.ROOT);
    return rule.getConditions().stream().filter((condition) -> condition.getOperator() == ConditionOperator.CONTAINS_KEYWORDS).flatMap((condition) -> condition.getValues().stream()).filter((value) -> value != null && !(value.isBlank())).filter((value) -> normalizedContent.contains(value.toLowerCase(Locale.ROOT))).toList();
  }

  protected ModerationDecision decisionFor(GeneratedModerationModel.PolicySpec policy, List<String> matchedKeywords) {
    if (policy == null || matchedKeywords == null || matchedKeywords.isEmpty()) {
      return ModerationDecision.APPROVED;
    }
    return policy.getDecision();
  }

  protected boolean isAutomatic(GeneratedModerationModel.PolicySpec policy) {
    return policy != null && policy.getMode() == ModerationMode.AUTOMATIC;
  }

  protected String statusFor(GeneratedModerationModel.PolicySpec policy, GeneratedModerationModel.AutomationRuleSpec rule, List<String> matchedKeywords) {
    if (policy == null || matchedKeywords == null || matchedKeywords.isEmpty()) {
      return ModerationDecision.APPROVED.name();
    }
    GeneratedModerationModel.ActionSpec action = primaryAction(rule);
    return (action == null ? policy.getDecision().name() : action.getKind().name());
  }

  protected String explanationFor(GeneratedModerationModel.PolicySpec policy, GeneratedModerationModel.AutomationRuleSpec rule, TriggerEvent trigger, List<String> matchedKeywords) {
    if (!(triggerMatches(policy, trigger))) {
      return "Trigger " + trigger + " does not match generated moderation policy.";
    }
    if (matchedKeywords == null || matchedKeywords.isEmpty()) {
      return "No generated moderation keywords matched.";
    }
    pt.isep.enorm.ref.service.generated.GeneratedModerationModel.ActionSpec action = primaryAction(rule);
    String actionText = (action == null ? "" : " Action " + action.getName() + " uses " + action.getKind() + ".");
    String ruleName = (rule == null ? "NoAutomationRule" : rule.getName());
    return ruleName + " matched generated moderation keywords: " + String.join(", ", matchedKeywords) + "." + actionText;
  }
}
